+      slidesSummaryController.setUrl(value);
+    },
+    resetSlidesSummaryState: () => {
+      slidesSummaryController.resetSummaryState();
+    },
+    setSlidesSummaryModel: (value) => {
+      slidesSummaryController.setModel(value);
+    },
+    setSlidesRunId,
+    headerSetStatus,
+  });
